const DEFAULT_CHAT_ID = '730354404';
const DEFAULT_REMINDER_TIME = '08:00';
const DEFAULT_REMINDER_TIMEZONE = 'Europe/Madrid';

const getVar = (key) => {
  if (typeof $vars !== 'undefined' && $vars[key] != null) {
    return String($vars[key]);
  }
  if (typeof $env !== 'undefined' && $env[key] != null) {
    return String($env[key]);
  }
  if (typeof process !== 'undefined' && process.env && process.env[key] != null) {
    return String(process.env[key]);
  }
  return '';
};

const isTruthy = (value) => ['1', 'true', 'yes', 'on'].includes(String(value).toLowerCase());

const isValidTime = (value) => /^([01]\d|2[0-3]):([0-5]\d)$/.test(value);

const getLocalNow = (timeZone) => {
  const now = new Date();
  const formatter = new Intl.DateTimeFormat('en-CA', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
    weekday: 'long',
  });

  const parts = formatter.formatToParts(now).reduce((acc, part) => {
    if (part.type !== 'literal') {
      acc[part.type] = part.value;
    }
    return acc;
  }, {});

  return {
    iso: now.toISOString(),
    date: `${parts.year}-${parts.month}-${parts.day}`,
    time: `${parts.hour}:${parts.minute}`,
    weekday: parts.weekday || '',
  };
};

const previewEnabled = isTruthy(getVar('RC_TELEGRAM_PREVIEW_MODE'));
const previewChatRaw = getVar('RC_TELEGRAM_PREVIEW_CHAT_ID').trim();
if (previewEnabled && !previewChatRaw) {
  throw new Error('RC_TELEGRAM_PREVIEW_CHAT_ID is required when RC_TELEGRAM_PREVIEW_MODE is enabled.');
}

const reminderEnabled = isTruthy(getVar('RC_REMINDER_ENABLED'));
if (!reminderEnabled) {
  return [];
}

const reminderTime = (getVar('RC_REMINDER_TIME').trim() || DEFAULT_REMINDER_TIME);
if (!isValidTime(reminderTime)) {
  throw new Error('RC_REMINDER_TIME must use HH:MM (24-hour) format.');
}

const reminderTimezone = getVar('RC_REMINDER_TIMEZONE').trim() || DEFAULT_REMINDER_TIMEZONE;
let localNow;
try {
  localNow = getLocalNow(reminderTimezone);
} catch (error) {
  throw new Error(`Invalid reminder timezone: ${reminderTimezone}`);
}

const forceSend = isTruthy(getVar('RC_REMINDER_FORCE_SEND'));
if (!forceSend && localNow.time !== reminderTime) {
  return [];
}

const targetChatId = previewEnabled ? previewChatRaw : DEFAULT_CHAT_ID;
const runId = `reminder-${localNow.date}-${Math.random().toString(36).slice(2, 10)}`;

return [{
  json: {
    runId,
    status: 'reminder',
    createdAt: localNow.iso,
    chatId: targetChatId,
    previewMode: previewEnabled,
    previewChatId: targetChatId,
    reminderEnabled,
    reminderDate: localNow.date,
    reminderWeekday: localNow.weekday,
    reminderTime,
    reminderTimezone,
    reminderForceSend: forceSend,
    reminderKey: `${targetChatId}:${localNow.date}`,
    reminderOptInUsersCount: 1,
    reminder_opt_in_users_count: 1,
  }
}];
